def _money(value: Decimal) -> Decimal:
    return value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def validate_cart_items(cart_items: List[CartItem]) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart is empty.")

    validated_items = []
    subtotal = Decimal("0.00")

    for item in cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for product {item.product_id}.")
        if item.unit_price < 0:
            raise ValidationError(f"Invalid unit price for product {item.product_id}.")
        item_subtotal = item.subtotal()
        subtotal += item_subtotal
        validated_items.append(
            {
                "product_id": item.product_id,
                "name": item.name,
                "unit_price": _money(item.unit_price),
                "quantity": item.quantity,
                "subtotal": item_subtotal,
            }
        )

    return {"items": validated_items, "subtotal": _money(subtotal)}


def apply_discount_codes(
    user: User,
    validated_cart: Dict[str, Any],
    discount_codes: List[DiscountCode],
) -> Dict[str, Any]:
    subtotal = validated_cart["subtotal"]
    discount_total = Decimal("0.00")
    applied_discounts = []

    for code in discount_codes:
        if not code.is_allowed_for(user):
            raise PermissionError(f"User is not permitted to use discount code {code.code}.")

        if code.discount_type == "percent":
            discount_amount = (subtotal * (code.value / Decimal("100"))).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        elif code.discount_type == "fixed":
            discount_amount = _money(code.value)
        else:
            raise ValidationError(f"Unsupported discount type for code {code.code}.")

        discount_amount = min(discount_amount, subtotal - discount_total)
        if discount_amount < Decimal("0.00"):
            discount_amount = Decimal("0.00")

        discount_total += discount_amount
        applied_discounts.append(
            {
                "code": code.code,
                "discount_type": code.discount_type,
                "value": _money(code.value),
                "amount": discount_amount,
            }
        )

    discounted_subtotal = subtotal - discount_total
    if discounted_subtotal < Decimal("0.00"):
        discounted_subtotal = Decimal("0.00")

    return {
        **validated_cart,
        "applied_discounts": applied_discounts,
        "discount_total": _money(discount_total),
        "discounted_subtotal": _money(discounted_subtotal),
    }


def calculate_tax(checked_out: Dict[str, Any], tax_rate: Decimal) -> Dict[str, Any]:
    if tax_rate < 0:
        raise ValidationError("Tax rate cannot be negative.")

    taxable_amount = checked_out["discounted_subtotal"]
    tax_total = (taxable_amount * (tax_rate / Decimal("100"))).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    total = taxable_amount + tax_total

    return {
        **checked_out,
        "tax_rate": _money(tax_rate),
        "tax_total": _money(tax_total),
        "total": _money(total),
    }


def process_payment(user: User, taxed_order: Dict[str, Any], payment_method: Dict[str, Any]) -> PaymentResult:
    if not payment_method.get("token"):
        raise PaymentError("Missing payment token.")

    total = taxed_order["total"]
    if total <= Decimal("0.00"):
        return PaymentResult(success=True, transaction_id=f"free-{uuid.uuid4().hex}", raw_response={"status": "free"})

    transaction_id = f"txn_{uuid.uuid4().hex}"
    return PaymentResult(
        success=True,
        transaction_id=transaction_id,
        raw_response={
            "status": "approved",
            "user_id": user.user_id,
            "amount": str(total),
            "currency": payment_method.get("currency", "USD"),
        },
    )


def create_order_record(
    user: User,
    taxed_order: Dict[str, Any],
    payment_result: PaymentResult,
) -> OrderRecord:
    if not payment_result.success or not payment_result.transaction_id:
        raise CheckoutError("Cannot create order without successful payment.")

    return OrderRecord(
        order_id=f"ord_{uuid.uuid4().hex}",
        user_id=user.user_id,
        items=taxed_order["items"],
        subtotal=taxed_order["subtotal"],
        discount_total=taxed_order["discount_total"],
        tax_total=taxed_order["tax_total"],
        total=taxed_order["total"],
        payment_transaction_id=payment_result.transaction_id,
    )


def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_codes: Optional[List[DiscountCode]] = None,
    tax_rate: Decimal = Decimal("0.00"),
    payment_method: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    discount_codes = discount_codes or []
    payment_method = payment_method or {}

    validated_cart = validate_cart_items(cart_items)
