    taxed_order = calculate_tax(discounted_cart, tax_rate)
    payment_result = process_payment(user, taxed_order, payment_method)
    order = create_order_record(user, taxed_order, payment_result)

    return {
        "order": order,
        "payment": payment_result,
    }